import{_ as t,o as r,c as e,a2 as o}from"./chunks/framework.BWuWLRhz.js";const s="/assets/clash-meta-for-Android-01.CwyyrxX5.png",l="/assets/clash-meta-for-Android-02.CGGjGDyt.png",d="/assets/clash-meta-for-Android-03.B-1yUEwH.png",i="/assets/clash-meta-for-Android-04.BjdSMx7-.png",n="/assets/clash-meta-for-Android-05.BY3-nJQB.png",h="/assets/clash-meta-for-Android-06.MkH1WIcu.png",q=JSON.parse('{"title":"Clash Meta for Android","description":"Android 首选客户端 Clash Meta 图文配置教程，从复制订阅到启动连接六步完成。","frontmatter":{"description":"Android 首选客户端 Clash Meta 图文配置教程，从复制订阅到启动连接六步完成。"},"headers":[],"relativePath":"clients/android/clash-meta.md","filePath":"clients/android/clash-meta.md","lastUpdated":1783294793000}'),c={name:"clients/android/clash-meta.md"};function p(u,a,g,m,f,b){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="clash-meta-for-android" tabindex="-1">Clash Meta for Android <a class="header-anchor" href="#clash-meta-for-android" aria-label="Permalink to &quot;Clash Meta for Android&quot;">​</a></h1><blockquote><p><strong>Android 规则分流主力客户端</strong> | 功能完整、策略组灵活、兼容性高</p></blockquote><p><a href="https://github.com/MetaCubeX/ClashMetaForAndroid" target="_blank" rel="noreferrer">Clash Meta for Android</a> 基于 Clash Meta 内核，适合对规则分流、策略组、节点管理有较高要求的用户，也是自由港机场在 Android 上的首选推荐。</p><h2 id="协议支持" tabindex="-1">协议支持 <a class="header-anchor" href="#协议支持" aria-label="Permalink to &quot;协议支持&quot;">​</a></h2><table tabindex="0"><thead><tr><th>协议</th><th>支持状态</th><th>说明</th></tr></thead><tbody><tr><td>VMess / VLESS</td><td>支持</td><td>常用主流协议</td></tr><tr><td>Trojan</td><td>支持</td><td>TLS 伪装常见方案</td></tr><tr><td>Shadowsocks</td><td>支持</td><td>兼容老方案</td></tr><tr><td>Hysteria / WireGuard</td><td>支持</td><td>视订阅而定</td></tr></tbody></table><h2 id="系统要求" tabindex="-1">系统要求 <a class="header-anchor" href="#系统要求" aria-label="Permalink to &quot;系统要求&quot;">​</a></h2><ul><li>最低版本：Android 8.0 及以上</li><li>推荐版本：Android 10 及以上</li><li>存储空间：200MB 可用空间</li></ul><h2 id="下载与安装" tabindex="-1">下载与安装 <a class="header-anchor" href="#下载与安装" aria-label="Permalink to &quot;下载与安装&quot;">​</a></h2><ul><li>Android universal（直链）：<a href="https://github.com/MetaCubeX/ClashMetaForAndroid/releases/download/v2.11.24/cmfa-2.11.24-meta-universal-release.apk" target="_blank" rel="noreferrer">下载 APK</a></li><li>Android universal（镜像加速）：<a href="https://gh.xxooo.cf/https://github.com/MetaCubeX/ClashMetaForAndroid/releases/download/v2.11.24/cmfa-2.11.24-meta-universal-release.apk" target="_blank" rel="noreferrer">下载 APK</a></li><li>当前参考版本：<code>v2.11.24</code></li></ul><p>安装步骤：下载 universal 包后安装 APK，首次启动时允许 VPN 权限即可。</p><h2 id="配置教程" tabindex="-1">配置教程 <a class="header-anchor" href="#配置教程" aria-label="Permalink to &quot;配置教程&quot;">​</a></h2><h3 id="步骤一-复制订阅链接" tabindex="-1">步骤一：复制订阅链接 <a class="header-anchor" href="#步骤一-复制订阅链接" aria-label="Permalink to &quot;步骤一：复制订阅链接&quot;">​</a></h3><p>登录<a href="https://freedomport.cc/#/dashboard" target="_blank" rel="noreferrer">自由港机场会员中心</a>，在「我的订阅」的订阅链接区域，点击右侧的<strong>复制</strong>按钮，复制你的专属订阅链接。</p><p><img src="'+s+'" alt="在会员中心复制订阅链接"></p><h3 id="步骤二-进入配置管理" tabindex="-1">步骤二：进入配置管理 <a class="header-anchor" href="#步骤二-进入配置管理" aria-label="Permalink to &quot;步骤二：进入配置管理&quot;">​</a></h3><p>打开 Clash Meta for Android，此时顶部显示「已停止」。点击下方的<strong>配置</strong>卡片，进入配置管理页面。</p><p><img src="'+l+'" alt="点击配置卡片"></p><h3 id="步骤三-新建配置" tabindex="-1">步骤三：新建配置 <a class="header-anchor" href="#步骤三-新建配置" aria-label="Permalink to &quot;步骤三：新建配置&quot;">​</a></h3><p>在配置列表页，点击右上角的<strong>加号（+）</strong>，开始新建一个配置。</p><p><img src="'+d+'" alt="点击右上角加号新建配置"></p><h3 id="步骤四-选择从-url-导入" tabindex="-1">步骤四：选择从 URL 导入 <a class="header-anchor" href="#步骤四-选择从-url-导入" aria-label="Permalink to &quot;步骤四：选择从 URL 导入&quot;">​</a></h3><p>在「创建配置」页面，选择 <strong>URL（从 URL 导入）</strong>。</p><p><img src="'+i+'" alt="选择从 URL 导入"></p><h3 id="步骤五-填写配置信息并保存" tabindex="-1">步骤五：填写配置信息并保存 <a class="header-anchor" href="#步骤五-填写配置信息并保存" aria-label="Permalink to &quot;步骤五：填写配置信息并保存&quot;">​</a></h3><p>在配置详情页依次完成四步：</p><ol><li><strong>名称</strong>：填写一个便于识别的名称，例如 <code>FREEDOMPORT</code></li><li><strong>URL</strong>：粘贴步骤一复制的订阅链接</li><li><strong>自动更新</strong>：填入 <code>1440</code>（单位为分钟，即每 24 小时自动更新一次订阅）</li><li>完成后点击右上角的<strong>保存</strong>图标</li></ol><p><img src="'+n+'" alt="填写名称、订阅地址、自动更新并保存"></p><p>保存后应用会自动拉取节点配置，稍等片刻即可完成导入。</p><h3 id="步骤六-启动连接" tabindex="-1">步骤六：启动连接 <a class="header-anchor" href="#步骤六-启动连接" aria-label="Permalink to &quot;步骤六：启动连接&quot;">​</a></h3><p>回到主界面，此时「配置」已显示为激活状态。点击顶部卡片右侧的<strong>点击启动</strong>按钮，首次连接时允许系统的 VPN 请求，即可开始使用。</p><p><img src="'+h+'" alt="点击启动开始连接"></p><p>启动成功后，打开浏览器访问外网验证是否连接正常。</p><h2 id="日常使用" tabindex="-1">日常使用 <a class="header-anchor" href="#日常使用" aria-label="Permalink to &quot;日常使用&quot;">​</a></h2><ul><li><strong>更新节点</strong>：看到节点上新公告后，进入配置列表，点击对应配置右侧的菜单选择「更新」，或依赖已设置的自动更新</li><li><strong>切换节点</strong>：在主界面进入「代理」页面，选择延迟更低的节点或策略组</li><li><strong>结束使用</strong>：点击顶部卡片停止运行即可恢复直连</li></ul><h2 id="进阶功能" tabindex="-1">进阶功能 <a class="header-anchor" href="#进阶功能" aria-label="Permalink to &quot;进阶功能&quot;">​</a></h2><ul><li><strong>规则分流</strong>：支持域名、IP、GeoIP 规则，可按直连 / 代理 / 拒绝分流，国内应用直连、国外走代理</li><li><strong>策略组</strong>：支持自动选择、手动选择、负载均衡，节点异常时可快速切换</li><li><strong>状态监控</strong>：实时流量统计、规则命中与连接日志查看</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q: 导入订阅后没有节点？</strong> A: 先手动更新配置；确认订阅链接可访问；确认套餐在有效期内、流量未用完。</p><p><strong>Q: 已连接但无法访问网站？</strong> A: 切换节点重试；检查是否已授予 VPN 权限；确认代理模式为规则或全局。</p><p><strong>Q: 节点延迟都很高？</strong> A: 先更换网络环境（如切换 Wi-Fi / 蜂窝网络），再切换到距离更近的节点组。</p><p>更多问题见<a href="./../../guide/faq">常见问题 FAQ</a>，或通过<a href="./../../support">联系支持</a>获取帮助。</p><hr><blockquote><p>最后更新：2026 年 3 月 28 日 · 适用版本 Clash Meta for Android v2.11.24</p></blockquote>',43)])])}const A=t(c,[["render",p]]);export{q as __pageData,A as default};
